import{_ as i,o as t,c as s,ae as o}from"./chunks/framework.Czhw_PXq.js";const p="/assets/image-20260516165558751.C1KfdxD5.png",r="/assets/image-20260516215549354.BU-d0mLZ.png",n="/assets/image-20260516220321170.Cu6tJz7-.png",h=JSON.parse('{"title":"1. 第一讲","description":"","frontmatter":{},"headers":[],"relativePath":"posts/价值投资/价值投资.md","filePath":"posts/价值投资/价值投资.md"}'),a={name:"posts/价值投资/价值投资.md"};function e(g,l,u,_,m,c){return t(),s("div",null,[...l[0]||(l[0]=[o('<h1 id="_1-第一讲" tabindex="-1">1. 第一讲 <a class="header-anchor" href="#_1-第一讲" aria-label="Permalink to &quot;1. 第一讲&quot;">​</a></h1><p><strong>价值投资的定义</strong></p><p>以显著低于企业<strong>内生价值</strong>的<strong>折扣价格</strong>买入在自己<strong>能力圈</strong>范围之内的公司股权，从而获得足够的<strong>安全边际</strong>，保护投资本金在<strong>重大风险</strong>事件发生的情况下不会遭受实质性的经济损失，长期持有，通过公司本身内生价值的增长，及其价格对价值的回归来取得长期良好可靠的回报。</p><p><strong>价值投资的基本理念</strong></p><ul><li>股票不仅仅是可以买卖的证券，它代表对公司所有权的证书，是对公司部分所有权</li><li>市场只是个工具，是为你服务的，在大多数时间里，它不能告诉你真正的价值是什么</li><li>投资活动的本质是对未来的预测，预测的本质是概率分布，买入价要具备足够的安全边际</li><li>投资人可以通过长期的努力建立起自己的能力圈，没有边界的能力不是真正的能力</li></ul><p><strong>价值投资的理论框架</strong></p><ul><li>对股东的理解 <ul><li>公司、股权、股票和股价</li></ul></li><li>对投资风险的理解及市场先生的概念和理解</li><li>安全边际的概念和理解 <ul><li>净流动资产股票及捡烟屁股</li><li>用合理的价格买入优质企业的股票</li><li>经济护城河</li></ul></li><li>能力圈的概念和理解 <ul><li>能力圈的边界</li><li>对知识的诚实</li></ul></li><li>对全球经济和财富本质的理解</li><li>价值投资的方法论</li></ul><p><strong>公司的起源</strong></p><p>• 15世纪末之后，由于新大陆的发现和新航线的开辟，刺激了远洋贸易的发展，欧洲商人活动的领域从地中海周围扩展到了大西洋，东西半球各地贸易额大幅度增长。远洋贸易的发展迫切需要组建一批大型贸易公司，于是在西欧各国重商主义政府的支持下，一批特许贸易公司纷纷出现。</p><p>• 由于当时西欧各国盛行重商主义，政府不承认贸易自由，建立贸易公司须取得皇家特许。上述贸易公司是以承担某些义务换取皇家&quot;特许状&quot;才得以成立的，并在承担一定义务的同时，也就拥有了垄断性特权，或者垄断经营某一行业，或者垄断海外特定地区的殖民活动。英国在詹姆士一世（1603～1625年）在位时期确认了上述特许贸易公司的法人地位。</p><ul><li>特许贸易公司取得了法人地位，意味着在法律上把它们同在若干个合伙人的自然人财产基础上营运的合伙制企业区别开来，承认它们具有同一个独立的自然人相同的民事权利能力和民事行为能力。</li></ul><p>• 第一家永久性公司是1602年成立的荷兰东印度公司，它已具有公司的一些基本特征：靠募集股金建立，具有法人地位，由董事会领导下的经理人员来经营等。该公司在组建时，56.9%的股份为阿姆斯特丹商会拥有，其余的面向全国招募；公司设立股东大会作为最高权力机构；由股东大会选出60名董事组成董事会，为公司决策机构；另选17人组成经理会，为执行机构，主持日常事务；公司所得按股份分红。</p><p>• 这些特许贸易公司虽然具有一些公司的基本特征，但它们都是靠政府（或皇家）的政治权力特许建立的，拥有特它们的股票也被视为一种特权，因此不能被认为是严格意义上的现代公司。</p><p>• 18世纪初叶，一些商人在没有取得皇家&quot;特许状&quot;的情况下，模仿特许贸易公司的组织形式，通过发行股票来吸引投资者，组建合股公司（Joint-stock Company）。合股公司没有皇家的特许状，其股票可以自由转让，股东只负有限责任，公司由被股东集体授权的经理人员来经营。</p><p>• 合股公司的出现和流行推动了法律制度向赋予合股公司以法人地位的方向变革。</p><ul><li>英国议会首先在1825年不再禁止创办民间合股公司；1834年又授权君主向合股公司发放特许证书，使之具有通过政府官员进行代理诉讼的权利。1844年通过了公司法，规定建立公司不必事先获得特许，只要通过简单程序就可以获得登记；1856年正式确认了注册公司对债务只负有限的赔偿责任。</li></ul><hr><p><strong>兴趣阅读：</strong>《公司的历史》（The Company: A Short History of a Revolutionary Idea）作者：约翰·米克勒斯维特（John Micklethwait）、阿德里安·伍尔德里奇（Adrian Wooldridge），译者：夏荷立，出版社：安徽人民出版社 2022.7</p><p><strong>内生价值VS市场价格</strong></p><ul><li>商品交换中的商品价格vs价值</li><li>股票价值=企业所有权价值$\\times$股票所代表的股权份额=企业未来回报的价值$\\times$ 股票所代表的股权份额=企业内生价值$\\times$股票所代表的股权份额</li><li>股票价值与股票价格的关系</li><li>企业的内生价值的来源：资产、盈利模式、未来成长潜力</li></ul><p><img src="'+p+'" alt="image-20260516165558751"></p><p>什么是风险：</p><p>是真正会对我们所看的公司的生意会造成实质性影响的事件，而且是破坏性的事件，它才是真正的风险。所以我们要看的是这样的事件发生的概率。</p><p>什么样的事件的发生会对我们的公司的经营会产生巨大的负面影响？</p><p>安全边际：企业的内生价值和市场价格之间的一个折扣，目的是为了给投资者提供一个保护。</p><p>如何定义企业的内生价值？这个折扣需要多大？价格一般情况下是一个可以确定的一个参数，市场会提供，但是价值呢？价值需要一个计算的过程，存在很多的不确定性，不可量化性。</p><p><strong>什么是经济护城河</strong></p><p>一家企业所建立起来的长期可持续的竞争优势，以保护其盈利不受竞争对手的侵蚀。经济护城河所隐含的丰富内涵：宽度、深度、强度、持久性等。</p><p><strong>什么是能力圈</strong></p><ul><li>我们通过学习以及经验的积累所建立起来的、对某些事物和领域的有用的知识和理解</li><li>能力圈是有边界的</li><li>能力圈为我们提供了认知上的竞争优势</li></ul><p><img src="'+r+'" alt="image-20260516215549354"></p><p><strong>企业盈利与经济增长的内在逻辑</strong></p><p><img src="'+n+'" alt="image-20260516220321170"></p><p><strong>财富是经济体中的购买力占比</strong></p><ul><li>当经济进入到持续累进增长的时代，真正的财富应该用我们在整个经济体中所占有的购买力比例来衡量</li><li>投资的根本目的是保存和增加我们的购买力</li><li>优秀的公司能够持续的增加内在价值</li><li>价值投资的目标是在最具活力的经济体中，持有最具活力的公司股份，从而保持和增长财富</li></ul>',35)])])}const f=i(a,[["render",e]]);export{h as __pageData,f as default};
